import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Movie {
  title: string;
  rating: number;
  genre: string;
  runtime: string;
}

interface MoviesData {
  topMovies: Movie[];
}

export default function Widget() {
  const moviesData = response.data as MoviesData;
  const { topMovies } = moviesData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2D2D2D' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FF6F61', mb: 1 }}>
            Top Movies
          </Typography>

          {topMovies.map((movie, index) => (
            <Box key={index} sx={{ bgcolor: '#1E1E1E', borderRadius: 1, p: 1.5, mb: 1 }}>
              <Stack spacing={1}>
                <Typography variant="body1" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                  {movie.title}
                </Typography>
                <Stack direction="row" spacing={0.5}>
                  <Chip label={movie.genre} sx={{ fontSize: '10px', bgcolor: '#4DB6AC', color: '#FFFFFF' }} />
                  <Chip label={`${movie.rating} / 10`} sx={{ fontSize: '10px', bgcolor: '#FF6F61', color: '#FFFFFF' }} />
                  <Chip label={movie.runtime} sx={{ fontSize: '10px', bgcolor: '#4DB6AC', color: '#FFFFFF' }} />
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
